sql:
SELECT AVG(time_sec) AS average_time
FROM time_series_data
WHERE simulation_id = 1 AND time_sec BETWEEN 0.001 AND 0.01;

SELECT AVG(parameter_value) AS average_temperature
FROM parameters
WHERE parameter_name = 'temperature';

SELECT COUNT(DISTINCT user_id) AS unique_user_count
FROM user_access_logs
WHERE SUBSTR(access_datetime, 1, 10) = '2023-03-01';

